import{_ as i,o as e,c as a,ag as r}from"./chunks/framework.f_9xDHrT.js";const p=JSON.parse('{"title":"诱饵技能的特性","description":"","frontmatter":{},"headers":[],"relativePath":"reference/lure.md","filePath":"reference/lure.md","lastUpdated":null}'),t={name:"reference/lure.md"};function u(o,l,n,s,c,d){return e(),a("div",null,[...l[0]||(l[0]=[r('<h1 id="诱饵技能的特性" tabindex="-1">诱饵技能的特性 <a class="header-anchor" href="#诱饵技能的特性" aria-label="Permalink to &quot;诱饵技能的特性&quot;">​</a></h1><blockquote><p>在此不重复说明诱饵技能在游戏中的信息。</p></blockquote><p>诱饵技能的特性分两部分：游戏机制与副作用。</p><h2 id="游戏机制" tabindex="-1">游戏机制 <a class="header-anchor" href="#游戏机制" aria-label="Permalink to &quot;游戏机制&quot;">​</a></h2><ul><li><strong>权重与锁定效果：</strong><ul><li>诱饵技能使用后会获得状态效果 <ul><li>每层提升一定的对应体型鱼类的咬饵权重。 <ul><li>可视作往池子中放入更多该体型鱼类。</li></ul></li><li>每层提升的咬饵权重都会比前一层要高。第三层最高。 <ul><li>实测的权重比例每层分别为 1.6、2、6。<a href="https://nga.178.com/read.php?tid=40940481" target="_blank" rel="noreferrer">（来源）</a></li></ul></li></ul></li><li>每次获得状态效果都有概率触发体型锁定效果，使对应体型的鱼类必定咬饵。 <ul><li>在获得锁定效果后再次使用，将失去锁定效果。</li><li>如果提示语后面是 3 个感叹号则为触发锁定效果。 <ul><li>例如有「现在感觉能钓到大型猎物！！！」则下次咬饵必定是大型鱼类。</li></ul></li></ul></li></ul></li><li><strong>鱼影：</strong><ul><li>某些鱼类的咬饵需要使用对应体型的诱饵技能，直到触发特殊的鱼影提示词。 <ul><li>诱饵技能的层数越高，触发的概率越大。</li><li>触发时，对应鱼类的咬饵权重相比其他情况时最高。 <ul><li>如果再次使用将不会是最高概率，但保留已触发的状态。</li></ul></li></ul></li></ul></li></ul><h2 id="副作用" tabindex="-1">副作用 <a class="header-anchor" href="#副作用" aria-label="Permalink to &quot;副作用&quot;">​</a></h2><p>由于服务器的通信需要时间，且需要特别的逻辑来满足游戏机制，诱饵技能将产生额外的副作用。</p><h3 id="咬饵时间" tabindex="-1">咬饵时间 <a class="header-anchor" href="#咬饵时间" aria-label="Permalink to &quot;咬饵时间&quot;">​</a></h3><ul><li><strong>咬饵真空期：</strong><ul><li>诱饵技能使用后将立刻进入咬饵真空期，在这段时间内，客户端不会收到任何咬饵。 <ul><li>咬饵真空期由 2 段时间组成：不定时长的通信期和固定时长的咬饵延后期。 <ul><li>由于通信和服务器处理需要时间，从使用到服务器返回诱饵结果（黑底漂浮提示文本）约占咬饵真空期 0.5~2 秒。</li><li>在收到诱饵结果后处于咬饵延后期，这段时间固定占 3.5 秒。</li></ul></li></ul></li></ul></li></ul><blockquote><p>以下均为模拟解释，与实际情况有偏差。例如在抛竿后，实际上在等待一段时间后才能使用诱饵技能。</p></blockquote><ul><li><strong>对咬饵时间的影响：</strong><ul><li>假设鱼 A 会在抛竿后第 5 秒咬饵，假设本次的咬饵真空期占 4 秒。 <ul><li>当在抛竿后立刻使用 1 次诱饵技能，真空期结束后将是第 4 秒，此时鱼 A 会正常在第 5 秒咬饵。</li><li>当在抛竿后的第 2 秒使用 1 次诱饵技能，真空期结束后将是 6 秒（2 + 4）。 <ul><li>此时真空期将预期的咬饵时间包含了，鱼 A 的咬饵将被推迟到真空期结束后，也就是第 6 秒，表现就是鱼 A 的咬饵时间比预期的更晚。</li></ul></li></ul></li></ul></li></ul><h3 id="重新随机" tabindex="-1">重新随机 <a class="header-anchor" href="#重新随机" aria-label="Permalink to &quot;重新随机&quot;">​</a></h3><ul><li><strong>重随咬饵结果：</strong><ul><li>假如鱼 A 在第 5 秒仍未咬饵，也就是本次抛竿的咬饵结果不是鱼 A 时。</li><li>在第 6 秒使用 1 次诱饵技能，将使服务器重新下发咬饵结果，如果本次咬饵结果是鱼 A，那么鱼 A 将在第 10 秒（6 + 4）咬饵。</li></ul></li></ul><blockquote><ul><li><strong>你无法通过诱饵技能来避开特定鱼类的咬饵区间：</strong><br> 例如，虽然在使用诱饵技能影响咬饵时间后，表现为鱼 A 在其预期的最长咬饵时间后才咬饵，<br> 但即使连续使用诱饵技能来推迟咬饵，如果服务器重新随机后的咬饵结果仍是鱼 A，那么无论最终的咬饵时间超过鱼 A 的预期最长咬饵时间多久，鱼 A 都会咬饵。</li></ul></blockquote>',14)])])}const _=i(t,[["render",u]]);export{p as __pageData,_ as default};
